// Define a function to validate the ref name
var validateRefName = function(refName) {
    // Check for invalid Unicode sequences using punycode
    try {
        punycode.ucs2.encode(refName);
    } catch (e) {
        return false;
    }

    // Check against forbidden characters
    if (/[!@,\[\]\s\t\n\r\~\:\<\>]/.test(refName)) {
        return false;
    }

    return true;
};

