class Solution:
    def validateRefName(self, refName: str) -> bool:
        # Check for invalid Unicode sequences using unicodedata
        try:
            unicodedata.normalize('NFKC', refName)
        except unicodedata.NormalizeError:
            return False

        # Check against forbidden characters
        if any(c in refName for c in '!@,\[\]\s\t\n\r~:\<\>'): return False

        return True;

